def compute_score():
    from pptx import Presentation
    import os
    import re
    if not os.path.exists(modified_ppt_path):
        return "Modified PPT not found.", 0.0
    prs = Presentation(modified_ppt_path)
    try:
        slide = prs.slides[2]
    except IndexError:
        return "Slide 3 does not exist in modified PPT.", 0.0
    for shape in slide.shapes:
        if shape.has_table:
            table = shape.table
            text_cells = [[cell.text.strip() for cell in row.cells] for row in table.rows]
            # Flatten for easier searching
            flat = [cell.lower() for row in text_cells for cell in row]
            has_male = any('male' in cell for cell in flat)
            has_female = any('female' in cell for cell in flat)
            # Check for at least one cell with a BMI range using <, >, or -
            has_range = any(re.search(r'\b[<>-–]\b', cell) or re.search(r'\d+\s*(?:-|–)\s*\d+', cell) for cell in flat)
            if has_male and has_female and has_range:
                return "Table contains Male, Female, and BMI ranges formatted with <, >, or -.", 1.0
            else:
                missing = []
                if not has_male:
                    missing.append('Male')
                if not has_female:
                    missing.append('Female')
                if not has_range:
                    missing.append('BMI range formatting')
                return f"Table missing: {', '.join(missing)}.", 0.0
    return "No table found on slide 3 to check content.", 0.0

